// ── Validate required fields ──────────────────────────────────────
const required = ['incidentId', 'severity', 'title', 'createdAt'];
for (const field of required) {
  if (!$json[field]) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// ── Severity mapping: P1->1, P2->2, P3->3, P4->4 ──────────────────
const sevMap = { P1: 1, P2: 2, P3: 3, P4: 4 };
const severityRank = sevMap[$json.severity];
if (!severityRank) {
  throw new Error(`Invalid severity: "${$json.severity}". Expected P1, P2, P3, or P4.`);
}

// ── dedupeKey formula: incidentId|severity|title ──────────────────
const dedupeKey = `${$json.incidentId}|${$json.severity}|${$json.title}`;

// ── Truncate description to 240 chars ─────────────────────────────
const desc = $json.description || '';
const descriptionShort = desc.length > 240 ? desc.slice(0, 237) + '...' : desc;

// ── Build clean notification message ──────────────────────────────
const correlationId = $json.metadata?.correlationId || '';
const notificationMessage = `[${$json.severity}] ${$json.incidentId} — ${$json.title} (corr=${correlationId})`;

return [{
  json: {
    ...$json,
    severityRank,
    dedupeKey,
    descriptionShort,
    correlationId,
    notificationMessage
  }
}];

// ── Check if this incident was already processed (idempotency) ─────
const staticData = $getWorkflowStaticData('global');
if (!staticData.processedKeys) {
  staticData.processedKeys = {};
}

const dedupeKey = $json.dedupeKey;
const isDuplicate = Boolean(staticData.processedKeys[dedupeKey]);

return [{ json: { ...$json, isDuplicate } }];

// ── Slack Notify with Exponential-Backoff Retry ──────────────────
// Retries on 429 (rate-limited) and 5xx (server errors).
// Does NOT retry on other 4xx (client errors).
// Max attempts: 5.  Backoff: 1s, 2s, 4s, 8s, 16s.

const incident = $json;
const url = 'http://localhost:4010/chat.postMessage';
const headers = {
  'Authorization': 'Bearer slack-test-token',
  'Content-Type': 'application/json'
};
const payload = {
  channel: '#oncall-alerts',
  text: incident.notificationMessage
};

const MAX_RETRIES = 5;

for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
  const response = await fetch(url, {
    method: 'POST',
    headers,
    body: JSON.stringify(payload)
  });

  if (response.status >= 200 && response.status < 300) {
    return [{ json: { ...incident, slackStatus: 'success', slackAttempts: attempt } }];
  }

  const retryable = response.status === 429 || response.status >= 500;
  if (retryable && attempt < MAX_RETRIES) {
    const delayMs = Math.pow(2, attempt - 1) * 1000;
    await new Promise(resolve => setTimeout(resolve, delayMs));
    continue;
  }

  return [{ json: { ...incident, slackStatus: 'failed', slackStatusCode: response.status, slackAttempts: attempt } }];
}

return [{ json: { ...incident, slackStatus: 'failed', slackAttempts: MAX_RETRIES } }];

// ── Persist Slack failure in workflow static data ────────────────
const staticData = $getWorkflowStaticData('global');
if (!staticData.failures) staticData.failures = [];

const record = {
  timestamp: new Date().toISOString(),
  incidentId: $json.incidentId,
  service: 'slack',
  statusCode: $json.slackStatusCode ?? null,
  attempts: $json.slackAttempts
};

staticData.failures.push(record);

console.error(
  `[FAILURE] Slack | incident=${record.incidentId} | attempts=${record.attempts} | status=${record.statusCode}`
);

return [{ json: $json }];

// ── O365 Email with Exponential-Backoff Retry ────────────────────
// Retries on 429 and 5xx only.  Max attempts: 5.

const incident = $json;
const url = 'http://localhost:4020/me/sendMail';
const headers = {
  'Authorization': 'Bearer ms-test-token',
  'Content-Type': 'application/json'
};
const payload = {
  message: {
    subject: `[${incident.severity}] ${incident.incidentId} — ${incident.title}`,
    body: {
      contentType: 'Text',
      content: `${incident.descriptionShort}\n\nCorrelationId: ${incident.correlationId}\nCreatedAt: ${incident.createdAt}`
    },
    toRecipients: [{ emailAddress: { address: incident.ownerEmail } }]
  },
  saveToSentItems: false
};

const MAX_RETRIES = 5;

for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
  const response = await fetch(url, {
    method: 'POST',
    headers,
    body: JSON.stringify(payload)
  });

  if (response.status >= 200 && response.status < 300) {
    return [{ json: { ...incident, o365Status: 'success', o365Attempts: attempt } }];
  }

  const retryable = response.status === 429 || response.status >= 500;
  if (retryable && attempt < MAX_RETRIES) {
    const delayMs = Math.pow(2, attempt - 1) * 1000;
    await new Promise(resolve => setTimeout(resolve, delayMs));
    continue;
  }

  return [{ json: { ...incident, o365Status: 'failed', o365StatusCode: response.status, o365Attempts: attempt } }];
}

return [{ json: { ...incident, o365Status: 'failed', o365Attempts: MAX_RETRIES } }];

// ── Persist O365 failure in workflow static data ─────────────────
const staticData = $getWorkflowStaticData('global');
if (!staticData.failures) staticData.failures = [];

const record = {
  timestamp: new Date().toISOString(),
  incidentId: $json.incidentId,
  service: 'o365',
  statusCode: $json.o365StatusCode ?? null,
  attempts: $json.o365Attempts
};

staticData.failures.push(record);

console.error(
  `[FAILURE] O365 | incident=${record.incidentId} | attempts=${record.attempts} | status=${record.statusCode}`
);

return [{ json: $json }];

// ── Mark dedupeKey as processed so replays are skipped ───────────
const staticData = $getWorkflowStaticData('global');
if (!staticData.processedKeys) staticData.processedKeys = {};

staticData.processedKeys[$json.dedupeKey] = new Date().toISOString();

return [{ json: $json }];
